export type PipelineStatus =
  | "New"
  | "Contacted"
  | "Engaged"
  | "Qualified"
  | "Proposal"
  | "Won"
  | "Lost";

export const PIPELINE_STATUSES: PipelineStatus[] = [
  "New", "Contacted", "Engaged", "Qualified", "Proposal", "Won", "Lost",
];

// Contact-readiness is derived from real enrichment data (not pipeline progress).
export type Readiness = "ready" | "partial" | "thin";

export interface Lead {
  id: string;
  name: string;
  dba: string;
  contact: string;
  aerial: boolean;       // holds aerial pest-applicator license (already flying)
  codes: string[];       // CDA ag categories held (101/102/103)
  phone: string;
  email: string;
  website: string;
  city: string;
  county: string;
  state: string;
  zip: string;
  lat: number | null;
  lng: number | null;
  employees: number | string | "";
  revenue: string;       // est. annual revenue (Apollo), e.g. "$12.5M"
  status: PipelineStatus;
  readiness: Readiness;
}

